CREATE OR REPLACE FUNCTION f_get_collateral_desc ( as_conno text , as_collateral_no text , as_colltype_code text , as_ref_own_no text ) RETURNS varchar AS $body$
DECLARE

    ls_collateral_desc varchar(100);
    ls_member_name varchar(100);
    ls_member_group_no varchar(10);

BEGIN

    select pka_com_function.fp_get_member_name(as_colltype_code) as member_name
    ,(select member_group_no
        from sc_mem_m_membership_registered 
        where membership_no = as_colltype_code
     ) as member_group_no
    into STRICT ls_member_name , ls_member_group_no
;

    
    
    if length(trim(both as_ref_own_no)) > 7 then
    
        select sc_lon_m_contract_coll.collateral_description 
        into STRICT ls_member_name
        from sc_lon_m_contract_coll
        where loan_contract_no = as_conno
        and collateral_no = as_collateral_no
        and ref_own_no = as_ref_own_no;

    else
    
        select pka_com_function.fp_get_member_name(as_ref_own_no) 
        into STRICT ls_member_name  
;
        
    end if;



    if as_colltype_code = '01' then
        if length(trim(both as_ref_own_no)) > 7 then
            ls_collateral_desc := trim(both ls_member_name);
        else
            ls_collateral_desc := trim(both ls_member_name);
        end if;

--    elsif  as_colltype_code = '02' then
--        ls_collateral_desc := 'หุ้นค้ำประกัน';
--    elsif  as_colltype_code = '02' then
--        ls_collateral_desc := 'หุ้นค้ำประกัน';
--    elsif  as_colltype_code = '02' then
--        ls_collateral_desc := 'หุ้นค้ำประกัน';
--    else
--        ls_collateral_desc := 'หุ้นค้ำประกัน';
    end if;


  RETURN ls_collateral_desc;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
